<template>
  <div style="height: 600px;">
    <div :id="viewerId || 'viewer'"
      style="width:100%; min-height:80vh; margin-bottom:0; height:auto; min-height:650px;">
    </div>
  </div>
</template>

<script>
// NO CHANGES TO IMPORTS - keep them as they were when working
export default {
  props: {
    reportPath: {
      type: String,
      default: null
    },
    parameter: {
      type: Array,
      default: () => []
    },
    viewerId: {
      type: String,
      default: null
    }
  },
  data() {
    return {
      Token: null,
      reporturl: ''
    };
  },
  created() {
    // Set auth token
    this.Token = this.GetUserInfo.Token;
  },
  mounted() {
    this.reporturl = process.env.VUE_APP_REPORT_SERVER_URL;
    this.reloadViewer(); // Initialize viewer
  },
  watch: {
    // Watch for parameter or path change
    reportPath() {
      this.reloadViewer();
    },
    parameter() {
      this.reloadViewer();
    }
  },
  beforeDestroy() {
    // Clean up viewer when component destroyed
    const viewer = this.getViewer().data('boldReportViewer');
    if (viewer) {
      viewer.destroy();
    }
  },
  methods: {
    getViewer() {
      return $("#" + (this.viewerId || "viewer"));
    },
    reloadViewer() {
      // Destroy old viewer if exists
      const oldViewer = this.getViewer().data('boldReportViewer');
      if (oldViewer) oldViewer.destroy();

      // Clear the DOM container to remove any residual content/bindings
      this.getViewer().empty();

      // Reinitialize after DOM updates
      this.$nextTick(() => this.initializeReportViewer());
    },
    initializeReportViewer() {
      const el = this.getViewer();
      if (!this.reportPath) return; // Do not initialize if no path

      // MINIMAL CHANGE: Add hyperlink handler to the config
      el.boldReportViewer({
        reportServiceUrl: process.env.VUE_APP_TALYGEN_REPORT_API_URL + "/ReportViewer",
        reportPath: this.reportPath,
        processingMode: "Remote",
        parameters: this.parameter,
        reportServerUrl: this.reporturl,
        ajaxBeforeLoad: this.setReportToken,
        exportSettings: {
          exportOptions:
            ej.ReportViewer.ExportOptions.Excel |
            ej.ReportViewer.ExportOptions.Pdf
        },
        toolbarSettings: {
          showToolbar: true,
          showTooltip: true,
          autoHide: true,
          click: (event) => {
            // Always handle export properly
            if (event.command === "Export") {
              const viewerInstance = this.getViewer().data("boldReportViewer");
              if (viewerInstance) viewerInstance.exportReport();
            }
          }
        },
        // ADD THIS: Handle hyperlink clicks
        hyperlink: (args) => {
          this.handleHyperlinkClick(args);
        }
      });
    },
    setReportToken(args) {
      args.headers.push({ Key: "content-type", Value: "application/json;charset=UTF-8" });
      args.headers.push({ Key: "Authorization", Value: `Bearer ${this.Token}` });
    },
    handleHyperlinkClick(args) {
      console.log('Hyperlink clicked:', args);

      // Check if this is the "exceeded records" link
      if (args && args.hyperlink) {
        const href = args.hyperlink.toLowerCase();

        if (href.includes('divviewtakerequest') || href.includes('exceed')) {
          // Prevent the default navigation
          args.cancel = true;

          // Try to call the global function
          if (typeof window.handleExceededLink === 'function') {
            window.handleExceededLink();
          } else if (window.parent && typeof window.parent.handleExceededLink === 'function') {
            window.parent.handleExceededLink();
          } else {
            console.warn('handleExceededLink function not found');
          }
        }
        // Check if this is a line item details link
        else if (href.includes('handleviewlineitem') || href.includes('editinvoicelineitem')) {
          // Allow the JavaScript to execute (it will call the global function)
          // We don't cancel this, let the JavaScript run
          console.log('Line item details link clicked');
        }
        else if (
          href.includes('handleviewdescription') ||
          href.includes('handleviewreply') ||
          href.includes('handleviewattachment') ||
          href.includes('handleviewnote')
        ) {
          console.log('Popup link clicked for Description,Replies, Attachments & Notes');
          // DO NOT cancel
          // JavaScript will call window.parent.handleViewXxx(...)
        }
      }
    }


  }
};
</script>